import UIKit
import CryptoKit

class FinancialTransaction {
    var amount: Double
    var type: String
    var timestamp: Date
    
    init(amount: Double, type: String) {
        self.amount = amount
        self.type = type
        self.timestamp = Date()
    }
    
    func encrypt() -> Data? {
        let symmetricKey = SymmetricKey(size: .bits256)
        do {
            let encryptedData = try AES.GCM.seal(Data("\(amount),\(type),\(timestamp)".utf8), using: symmetricKey)
            return encryptedData.combined
        } catch {
            print("Encryption failed: \(error)")
            return nil
        }
    }
}

class AccountBalance {
    var balance: Double
    
    init(balance: Double) {
        self.balance = balance
    }
    
    func displayBalance() -> String {
        return "Current Balance: $\(balance)"
    }
}

class BankingAppViewController: UIViewController {
    @IBOutlet weak var balanceLabel: UILabel!
    var accountBalance: AccountBalance?
    var transactions: [FinancialTransaction] = []
    
    override func viewDidLoad() {
        super.viewDidLoad()
        accountBalance = AccountBalance(balance: 1000.0)
        displayCurrentBalance()
    }
    
    @IBAction func makeDeposit(_ sender: UIButton) {
        let transaction = FinancialTransaction(amount: 500, type: "Deposit")
        transactions.append(transaction)
        accountBalance?.balance += transaction.amount
        displayCurrentBalance()
    }
    
    @IBAction func makeWithdrawal(_ sender: UIButton) {
        if let balance = accountBalance?.balance, balance >= 200 {
            let transaction = FinancialTransaction(amount: 200, type: "Withdrawal")
            transactions.append(transaction)
            accountBalance?.balance -= transaction.amount
            displayCurrentBalance()
        } else {
            displayAlert("Insufficient funds")
        }
    }
    
    func displayCurrentBalance() {
        balanceLabel.text = accountBalance?.displayBalance()
    }
    
    func displayAlert(_ message: String) {
        let alert = UIAlertController(title: "Alert", message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default, handler: nil))
        present(alert, animated: true, completion: nil)
    }
}